import { DataModule, ModuleData } from '../../types';
import { fetchOpenMeteo } from '../apis/open-meteo';

export const weatherModule: DataModule = {
  name: 'Weather',
  async fetch(lat, lon) {
    const data = await fetchOpenMeteo('forecast', {
      latitude: lat.toString(),
      longitude: lon.toString(),
      current: 'temperature_2m,relative_humidity_2m,wind_speed_10m,surface_pressure',
    });
    return { raw: data, score: this.normalize(data.current) };
  },
  normalize(data: any) {
    // Simple temperature-based comfort (assuming 22C is ideal)
    const temp = data.temperature_2m;
    const diff = Math.abs(temp - 22);
    return Math.max(0, 1 - (diff / 20));
  }
};
import { DataModule } from '../../types';
import { fetchOpenMeteo } from '../apis/open-meteo';

export const uvModule: DataModule = {
  name: 'UV Index',
  async fetch(lat, lon) {
    const data = await fetchOpenMeteo('forecast', {
      latitude: lat.toString(),
      longitude: lon.toString(),
      hourly: 'uv_index',
    });
    // Using current or first hour index
    const uv = data.hourly.uv_index[0] || 0;
    return { raw: data, score: this.normalize(uv) };
  },
  normalize(uv: number) {
    // UV Index: 0-2=1.0, 3-5=0.7, 6-7=0.4, 8+=0.1
    if (uv <= 2) return 1.0;
    if (uv <= 5) return 0.7;
    if (uv <= 7) return 0.4;
    return 0.1;
  }
};
import { DataModule } from '../../types';

export const earthquakeModule: DataModule = {
  name: 'Earthquake',
  async fetch(lat, lon) {
    // USGS GeoJSON API
    const url = `https://earthquake.usgs.gov/fdsnws/event/1/query?format=geojson&latitude=${lat}&longitude=${lon}&maxradiuskm=500&limit=1`;
    const response = await fetch(url);
    const data = await response.json();
    return { raw: data, score: this.normalize(data) };
  },
  normalize(data: any) {
    if (!data.features || data.features.length === 0) return 1.0;
    const mag = data.features[0].properties.mag;
    // Simple magnitude normalization: < 3.0=1.0, 3-5=0.5, > 5=0.0
    if (mag < 3) return 1.0;
    if (mag < 5) return 0.5;
    return 0.0;
  }
};
